'use client'

import { useState } from 'react'

export default function GSTCalculator() {
  const [amount, setAmount] = useState('')
  const [gst, setGst] = useState('18')
  const [inclusive, setInclusive] = useState(false)
  const [result, setResult] = useState<{ tax: number; total: number } | null>(null)

  function calculate() {
    const A = parseFloat(amount || '0')
    const g = parseFloat(gst || '0') / 100
    if (!A) return setResult({ tax: 0, total: 0 })
    if (inclusive) {
      const base = A / (1 + g)
      const tax = A - base
      setResult({ tax, total: A })
    } else {
      const tax = A * g
      setResult({ tax, total: A + tax })
    }
  }

  function reset() {
    setAmount('')
    setGst('18')
    setInclusive(false)
    setResult(null)
  }

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">GST Calculator</h1>
      <div className="mt-4 max-w-md">
        <label className="block">
          <span>Amount (₹)</span>
          <input value={amount} onChange={e => setAmount(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <label className="block mt-3">
          <span>GST Rate (%)</span>
          <input value={gst} onChange={e => setGst(e.target.value)} className="w-full p-2 border rounded mt-1" />
        </label>

        <label className="flex items-center gap-2 mt-3">
          <input type="checkbox" checked={inclusive} onChange={e => setInclusive(e.target.checked)} />
          <span>Amount is GST inclusive</span>
        </label>

        <div className="flex gap-2 mt-4">
          <button onClick={calculate} className="px-4 py-2 bg-blue-600 text-white rounded">Calculate</button>
          <button onClick={reset} className="px-4 py-2 border rounded">Reset</button>
        </div>

        {result && (
          <div className="mt-4 p-4 bg-slate-50 dark:bg-slate-800 rounded">
            <div>GST Amount: ₹ {result.tax.toFixed(2)}</div>
            <div>Total: ₹ {result.total.toFixed(2)}</div>
          </div>
        )}
      </div>
    </main>
  )
}
